import json
try:
    parsed = json.loads(__args__['json_string'])
    print(json.dumps(parsed, indent=2, ensure_ascii=False))
except Exception as e:
    print(f'Error: {e}')

import base64
mode = __args__.get('mode', 'encode')
data = __args__['data']
try:
    if mode == 'encode':
        print(base64.b64encode(data.encode()).decode())
    else:
        print(base64.b64decode(data.encode()).decode())
except Exception as e:
    print(f'Error: {e}')

text = __args__['text']
mode = __args__.get('mode', 'upper')
if mode == 'upper': print(text.upper())
elif mode == 'lower': print(text.lower())
elif mode == 'reverse': print(text[::-1])
elif mode == 'title': print(text.title())
elif mode == 'snake_case': print('_'.join(text.lower().split()))
elif mode == 'count': print(f'chars={len(text)}, words={len(text.split())}, lines={len(text.splitlines())}')
else: print(f'Unknown mode: {mode}')

import math
expr = __args__['expression']
allowed = set('0123456789+-*/().,** %')
if all(c in allowed or c.isspace() for c in expr):
    try:
        result = eval(expr, {'__builtins__': {}, 'math': math, 'sqrt': math.sqrt, 'pi': math.pi, 'e': math.e})
        print(f'{expr} = {result}')
    except Exception as ex:
        print(f'Error: {ex}')
else:
    print('Error: Invalid expression. Only basic math allowed.')

import re
pattern = __args__['pattern']
text = __args__['text']
mode = __args__.get('mode', 'findall')
try:
    if mode == 'findall':
        matches = re.findall(pattern, text)
        print(f'Found {len(matches)} match(es):\n' + '\n'.join(matches))
    elif mode == 'match':
        m = re.match(pattern, text)
        print(f'Match: {m.group() if m else None}')
    elif mode == 'sub':
        repl = __args__.get('replacement', '')
        print(re.sub(pattern, repl, text))
except Exception as e:
    print(f'Error: {e}')

const mermaidCode = __args__.mermaid_code;
const outputPath = __args__.output_path || 'home/diagram.png';
if (!mermaidCode) return 'Error: mermaid_code is required';

if (typeof mermaid === 'undefined') {
  await new Promise((resolve, reject) => {
    const script = document.createElement('script');
    script.src = 'https://cdn.jsdelivr.net/npm/mermaid@10/dist/mermaid.min.js';
    script.onload = () => {
      mermaid.initialize({ startOnLoad: false });
      resolve();
    };
    script.onerror = reject;
    document.head.appendChild(script);
  });
}

const uniqueId = 'mermaid-' + Date.now();
const container = document.createElement('div');
container.style.visibility = 'hidden';
container.style.position = 'absolute';
container.id = uniqueId + '-container';
document.body.appendChild(container);

let svgText;
try {
  const { svg } = await mermaid.render(uniqueId, mermaidCode, container);
  svgText = svg;
} catch (err) {
  container.remove();
  return 'Mermaid Render Error: ' + err.message;
}
container.remove();

return await new Promise((resolve) => {
  const img = new Image();
  const svgBlob = new Blob([svgText], { type: 'image/svg+xml;charset=utf-8' });
  const url = URL.createObjectURL(svgBlob);

  img.onload = () => {
    const canvas = document.createElement('canvas');
    const scale = 2;
    canvas.width = img.naturalWidth * scale;
    canvas.height = img.naturalHeight * scale;

    const ctx = canvas.getContext('2d');
    ctx.fillStyle = 'white';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    ctx.drawImage(img, 0, 0, canvas.width, canvas.height);

    URL.revokeObjectURL(url);

    try {
      const pngDataUrl = canvas.toDataURL('image/png');
      if (window.amevaOS && typeof window.amevaOS.writeFile === 'function') {
        window.amevaOS.writeFile(outputPath, pngDataUrl);
        resolve('Successfully rendered Mermaid to PNG and saved to VFS: ' + outputPath);
      } else {
        resolve('Rendered successfully (VFS write skipped): ' + pngDataUrl.substring(0, 60) + '...');
      } 
    } catch (e) {
      resolve('Canvas toDataURL conversion error: ' + e.message);
    }
  };
  img.onerror = () => {
    URL.revokeObjectURL(url);
    resolve('Image load error during SVG conversion');
  };
  img.src = url;
});
